        defaultMenuOptionConfig: defaultMenuOptionConfig,
        renderMapContextMenu: renderMapContextMenu,
        renderConnectionContextMenu: renderConnectionContextMenu,
        renderEndpointContextMenu: renderEndpointContextMenu,
